 13→#[async_trait]
 14→pub trait SkillDiscoverer: Send + Sync {
 15→    /// Scan configured paths and return metadata for all discovered skills.
 16→    async fn discover(&self) -> anyhow::Result<Vec<SkillMetadata>>;
 17→}
