  1→use std::path::Path;
  2→
  3→use {
  4→    anyhow::{Context, bail},
  5→    serde::Deserialize,
  6→};
  7→
  8→use crate::types::{InstallKind, InstallSpec, SkillContent, SkillMetadata};
  9→
 10→/// Validate a skill name: lowercase ASCII, hyphens, 1-64 chars.
 11→pub fn validate_name(name: &str) -> bool {
 12→    !name.is_empty()
 13→        && name.len() <= 64
 14→        && name
 15→            .chars()
 16→            .all(|c| c.is_ascii_lowercase() || c.is_ascii_digit() || c == '-' || c == ':')
 17→        && !name.starts_with('-')
 18→        && !name.ends_with('-')
 19→        && !name.starts_with(':')
 20→        && !name.ends_with(':')
 21→        && !name.contains("--")
 22→        && !name.contains("::")
 23→}
 24→
 25→/// Parse a SKILL.md file into metadata only (frontmatter).
 26→pub fn parse_metadata(content: &str, skill_dir: &Path) -> anyhow::Result<SkillMetadata> {
 27→    let (frontmatter, _body) = split_frontmatter(content)?;
 28→    let mut meta: SkillMetadata =
 29→        serde_yaml::from_str(&frontmatter).context("invalid SKILL.md frontmatter")?;
 30→
 31→    if !validate_name(&meta.name) {
 32→        bail!(
 33→            "invalid skill name '{}': must be 1-64 lowercase alphanumeric/hyphen chars",
 34→            meta.name
 35→        );
 36→    }
 37→
 38→    merge_openclaw_requires(&frontmatter, &mut meta);
 39→    meta.path = skill_dir.to_path_buf();
 40→    Ok(meta)
 41→}
 42→
 43→/// Parse a SKILL.md file into full content (metadata + body).
 44→pub fn parse_skill(content: &str, skill_dir: &Path) -> anyhow::Result<SkillContent> {
 45→    let (frontmatter, body) = split_frontmatter(content)?;
 46→    let mut meta: SkillMetadata =
 47→        serde_yaml::from_str(&frontmatter).context("invalid SKILL.md frontmatter")?;
 48→
 49→    if !validate_name(&meta.name) {
 50→        bail!(
 51→            "invalid skill name '{}': must be 1-64 lowercase alphanumeric/hyphen chars",
 52→            meta.name
 53→        );
 54→    }
 55→
 56→    merge_openclaw_requires(&frontmatter, &mut meta);
 57→    meta.path = skill_dir.to_path_buf();
 58→    Ok(SkillContent {
 59→        metadata: meta,
 60→        body: body.to_string(),
 61→    })
 62→}
 63→
 64→// ── OpenClaw metadata extraction ────────────────────────────────────────────
 65→
 66→/// Helper struct to extract `metadata.openclaw.requires` and `metadata.openclaw.install`.
 67→#[derive(Deserialize, Default)]
 68→struct OpenClawRoot {
 69→    #[serde(default)]
 70→    metadata: Option<OpenClawMetadataWrap>,
 71→}
 72→
 73→#[derive(Deserialize, Default)]
 74→struct OpenClawMetadataWrap {
 75→    /// Our own namespace.
 76→    #[serde(default)]
 77→    openclaw: Option<OpenClawMeta>,
 78→    /// Original openclaw/clawdbot namespace.
 79→    #[serde(default)]
 80→    clawdbot: Option<OpenClawMeta>,
 81→    /// Moltbot namespace (some openclaw skills use this).
 82→    #[serde(default)]
 83→    moltbot: Option<OpenClawMeta>,
 84→}
 85→
 86→#[derive(Deserialize, Default)]
