 13→/// Install a skill repo from GitHub into the target directory.
 14→///
 15→/// Downloads the repo to `install_dir/<owner>-<repo>/`, auto-detects its format
 16→/// (SKILL.md, Claude Code `.claude-plugin/`, etc.), scans for skills using the
 17→/// appropriate adapter, and records the repo + skills in the manifest.
 18→pub async fn install_skill(source: &str, install_dir: &Path) -> anyhow::Result<Vec<SkillMetadata>> {
 19→    #[cfg(feature = "metrics")]
 20→    let start = std::time::Instant::now();
 21→
 22→    #[cfg(feature = "metrics")]
 23→    counter!(skills_metrics::INSTALLATION_ATTEMPTS_TOTAL).increment(1);
 24→
 25→    let (owner, repo) = parse_source(source)?;
 26→    let dir_name = format!("{owner}-{repo}");
 27→    let target = install_dir.join(&dir_name);
 28→
 29→    if target.exists() {
 30→        let manifest_path = ManifestStore::default_path()?;
 31→        let store = ManifestStore::new(manifest_path);
 32→        let manifest = store.load()?;
 33→        if manifest.find_repo(source).is_none() {
 34→            tokio::fs::remove_dir_all(&target).await?;
 35→        } else {
 36→            anyhow::bail!(
 37→                "repo directory already exists: {}. Remove it first with `skills remove`.",
 38→                target.display()
 39→            );
 40→        }
 41→    }
 42→
 43→    tokio::fs::create_dir_all(install_dir).await?;
 44→
 45→    #[cfg(feature = "metrics")]
 46→    counter!("moltis_skills_git_clone_fallback_total").increment(1);
 47→    let commit_sha = install_via_http(&owner, &repo, &target).await?;
 48→
 49→    // Auto-detect repo format and scan accordingly.
 50→    let format = detect_format(&target);
 51→    let (skills_meta, skill_states) = match format {
 52→        PluginFormat::Skill => scan_repo_skills(&target, install_dir).await?,
 53→        _ => match scan_with_adapter(&target, format) {
 54→            Some(result) => {
 55→                let entries = result?;
 56→                let relative = target
 57→                    .strip_prefix(install_dir)
 58→                    .unwrap_or(&target)
 59→                    .to_string_lossy()
 60→                    .to_string();
 61→                let meta: Vec<SkillMetadata> = entries.iter().map(|e| e.metadata.clone()).collect();
 62→                let states: Vec<SkillState> = entries
 63→                    .iter()
 64→                    .map(|e| SkillState {
 65→                        name: e.metadata.name.clone(),
 66→                        relative_path: relative.clone(),
 67→                        trusted: false,
 68→                        enabled: false,
 69→                    })
 70→                    .collect();
 71→                (meta, states)
 72→            },
 73→            None => {
 74→                let _ = tokio::fs::remove_dir_all(&target).await;
 75→                anyhow::bail!("no adapter available for format '{format}' in repo '{source}'");
 76→            },
 77→        },
 78→    };
 79→
 80→    if skills_meta.is_empty() {
 81→        let _ = tokio::fs::remove_dir_all(&target).await;
 82→        anyhow::bail!(
 83→            "repository contains no skills (checked {})",
 84→            target.display()
 85→        );
 86→    }
 87→
 88→    // Write manifest.
 89→    let manifest_path = ManifestStore::default_path()?;
 90→    let store = ManifestStore::new(manifest_path);
 91→    let mut manifest = store.load()?;
 92→
 93→    let now = std::time::SystemTime::now()
 94→        .duration_since(std::time::UNIX_EPOCH)
 95→        .unwrap_or_default()
 96→        .as_millis() as u64;
 97→
 98→    manifest.add_repo(RepoEntry {
 99→        source: format!("{owner}/{repo}"),
100→        repo_name: dir_name,
101→        installed_at_ms: now,
102→        commit_sha,
103→        format,
104→        skills: skill_states,
105→    });
106→    store.save(&manifest)?;
107→
108→    #[cfg(feature = "metrics")]
109→    histogram!(skills_metrics::INSTALLATION_DURATION_SECONDS).record(start.elapsed().as_secs_f64());
110→
111→    tracing::info!(count = skills_meta.len(), %source, "installed repo skills");
112→    Ok(skills_meta)
113→}
