135→/// Install by fetching a tarball from GitHub's API.
136→async fn install_via_http(
137→    owner: &str,
138→    repo: &str,
139→    target: &Path,
140→) -> anyhow::Result<Option<String>> {
141→    let url = format!("https://api.github.com/repos/{owner}/{repo}/tarball");
142→    let client = reqwest::Client::new();
143→    let commit_sha = fetch_latest_commit_sha(&client, owner, repo).await;
144→    let resp = client
145→        .get(&url)
146→        .header("User-Agent", "moltis-skills")
147→        .send()
148→        .await?;
149→
150→    if !resp.status().is_success() {
151→        anyhow::bail!("failed to fetch {}/{}: HTTP {}", owner, repo, resp.status());
152→    }
153→
154→    let bytes = resp.bytes().await?;
155→
156→    tokio::fs::create_dir_all(target).await?;
157→    let target_owned = target.to_path_buf();
158→    let owner_owned = owner.to_string();
159→    let repo_owned = repo.to_string();
160→    tokio::task::spawn_blocking(move || {
161→        let canonical_target = std::fs::canonicalize(&target_owned)?;
162→        let decoder = flate2::read::GzDecoder::new(&bytes[..]);
163→        let mut archive = tar::Archive::new(decoder);
164→        for entry in archive.entries()? {
165→            let mut entry = entry?;
166→            if entry.header().entry_type().is_symlink()
167→                || entry.header().entry_type().is_hard_link()
168→            {
169→                tracing::warn!(owner = %owner_owned, repo = %repo_owned, "skipping symlink/hardlink archive entry");
170→                continue;
171→            }
172→
173→            let path = entry.path()?.into_owned();
174→            let Some(stripped) = sanitize_archive_path(&path)? else {
175→                continue;
176→            };
177→
178→            let dest = target_owned.join(&stripped);
179→            if let Some(parent) = dest.parent() {
180→                std::fs::create_dir_all(parent)?;
181→                let canonical_parent = std::fs::canonicalize(parent)?;
182→                if !canonical_parent.starts_with(&canonical_target) {
183→                    anyhow::bail!("archive entry escaped install directory");
184→                }
185→            }
186→
187→            if dest.exists() {
188→                let meta = std::fs::symlink_metadata(&dest)?;
189→                if meta.file_type().is_symlink() {
190→                    anyhow::bail!("archive entry resolves to symlink destination");
191→                }
192→            }
193→
194→            if entry.header().entry_type().is_dir() {
195→                std::fs::create_dir_all(&dest)?;
196→                continue;
197→            }
198→
199→            entry.unpack(&dest)?;
200→        }
201→        Ok::<(), anyhow::Error>(())
202→    })
203→    .await??;
204→
205→    tracing::info!(%owner, %repo, "installed skill repo via HTTP tarball");
206→    Ok(commit_sha)
207→}
