209→async fn fetch_latest_commit_sha(
210→    client: &reqwest::Client,
211→    owner: &str,
212→    repo: &str,
213→) -> Option<String> {
214→    let url = format!("https://api.github.com/repos/{owner}/{repo}/commits?per_page=1");
215→    let response = client
216→        .get(url)
217→        .header("User-Agent", "moltis-skills")
218→        .send()
219→        .await
220→        .ok()?;
221→    if !response.status().is_success() {
222→        return None;
223→    }
224→    let value: serde_json::Value = response.json().await.ok()?;
225→    value
226→        .as_array()?
227→        .first()?
228→        .get("sha")?
229→        .as_str()
230→        .filter(|sha| sha.len() == 40)
231→        .map(ToOwned::to_owned)
232→}
233→
234→fn sanitize_archive_path(path: &Path) -> anyhow::Result<Option<PathBuf>> {
235→    let stripped: PathBuf = path.components().skip(1).collect();
236→    if stripped.as_os_str().is_empty() {
237→        return Ok(None);
238→    }
239→
240→    for component in stripped.components() {
241→        match component {
242→            Component::Normal(_) => {},
243→            Component::CurDir => {},
244→            Component::ParentDir | Component::RootDir | Component::Prefix(_) => {
245→                anyhow::bail!("archive contains unsafe path component: {}", path.display());
246→            },
247→        }
248→    }
249→
250→    Ok(Some(stripped))
251→}
