253→/// Recursively scan a cloned repo for SKILL.md files.
254→/// Returns (Vec<SkillMetadata>, Vec<SkillState>) — metadata for callers and
255→/// state entries for the manifest.
256→async fn scan_repo_skills(
257→    repo_dir: &Path,
258→    install_dir: &Path,
259→) -> anyhow::Result<(Vec<SkillMetadata>, Vec<SkillState>)> {
260→    // Check root SKILL.md (single-skill repo).
261→    let root_skill_md = repo_dir.join("SKILL.md");
262→    if root_skill_md.is_file() {
263→        let content = tokio::fs::read_to_string(&root_skill_md).await?;
264→        let mut meta = parse::parse_metadata(&content, repo_dir)?;
265→        meta.source = Some(crate::types::SkillSource::Registry);
266→
267→        let relative = repo_dir
268→            .strip_prefix(install_dir)
269→            .unwrap_or(repo_dir)
270→            .to_string_lossy()
271→            .to_string();
272→
273→        let state = SkillState {
274→            name: meta.name.clone(),
275→            relative_path: relative,
276→            trusted: false,
277→            enabled: false,
278→        };
279→        return Ok((vec![meta], vec![state]));
280→    }
281→
282→    // Multi-skill: recursively scan for SKILL.md.
283→    let mut skills_meta = Vec::new();
284→    let mut skill_states = Vec::new();
285→    let mut dirs_to_scan = vec![repo_dir.to_path_buf()];
286→
287→    while let Some(dir) = dirs_to_scan.pop() {
288→        let mut entries = match tokio::fs::read_dir(&dir).await {
289→            Ok(e) => e,
290→            Err(_) => continue,
291→        };
292→        while let Some(entry) = entries.next_entry().await? {
293→            let subdir = entry.path();
294→            if !subdir.is_dir() {
295→                continue;
296→            }
297→            let skill_md = subdir.join("SKILL.md");
298→            if skill_md.is_file() {
299→                let content = match tokio::fs::read_to_string(&skill_md).await {
300→                    Ok(c) => c,
301→                    Err(e) => {
302→                        tracing::debug!(?skill_md, %e, "skipping unreadable SKILL.md");
303→                        continue;
