        Arc<RwLock<HashMap<String, AbortHandle>>>,
        Arc<RwLock<HashMap<String, String>>>,
    ) {
        (
            Arc::new(RwLock::new(HashMap::new())),
            Arc::new(RwLock::new(HashMap::new())),
        )
    }

