                    format: PluginFormat::ClaudeCode,
                    skills: vec![SkillState {
                        name: "test-plugin:helper".into(),
                        relative_path: "plugin-repo".into(),
                        trusted: true,
                        enabled: true,
                    }],
                },
            ],
